import{_ as t,o,c as r,ag as a}from"./chunks/framework.YaIgwL5o.js";const c=JSON.parse('{"title":"Shapes & Elements","description":"","frontmatter":{},"headers":[],"relativePath":"features/shapes.md","filePath":"features/shapes.md"}'),n={name:"features/shapes.md"};function i(s,e,l,d,h,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="shapes-elements" tabindex="-1">Shapes &amp; Elements <a class="header-anchor" href="#shapes-elements" aria-label="Permalink to &quot;Shapes &amp; Elements&quot;">​</a></h1><p>Slides Editor includes a set of built-in vector shapes that you can place, style, and animate on any slide.</p><h2 id="inserting-a-shape" tabindex="-1">Inserting a shape <a class="header-anchor" href="#inserting-a-shape" aria-label="Permalink to &quot;Inserting a shape&quot;">​</a></h2><ol><li><p>Right-click on the slide canvas and choose <strong>Insert → Shape</strong>, or click the <strong>Shape</strong> button in the Insert toolbar.</p></li><li><p>A submenu shows the available shape types:</p><ul><li><strong>Rectangle</strong> — filled or outlined box; supports rounded corners</li><li><strong>Ellipse / Circle</strong> — oval or perfect circle (hold <code>Shift</code> while dragging to constrain to circle)</li><li><strong>Line</strong> — straight line with optional arrowheads at either end</li><li><strong>Arrow</strong> — single or double-headed arrow</li><li><strong>Triangle</strong> — equilateral, right-angle, or isosceles</li><li><strong>Star</strong> — 4-, 5-, or 6-pointed star</li></ul></li><li><p>Click the desired shape. It is placed at the center of the slide.</p></li></ol><h2 id="resizing-and-positioning" tabindex="-1">Resizing and positioning <a class="header-anchor" href="#resizing-and-positioning" aria-label="Permalink to &quot;Resizing and positioning&quot;">​</a></h2><ul><li><strong>Drag</strong> the element to reposition it.</li><li><strong>Drag a corner handle</strong> to resize (hold <code>Shift</code> to lock aspect ratio).</li><li><strong>Drag the rotation handle</strong> (circle above the element) to rotate; hold <code>Shift</code> to snap to 15° increments.</li><li>Use the <strong>Position &amp; Size</strong> panel on the right to enter exact pixel values for X, Y, width, and height.</li></ul><h2 id="styling-shapes" tabindex="-1">Styling shapes <a class="header-anchor" href="#styling-shapes" aria-label="Permalink to &quot;Styling shapes&quot;">​</a></h2><p>With a shape selected, the right panel shows styling options:</p><table tabindex="0"><thead><tr><th>Property</th><th>Options</th></tr></thead><tbody><tr><td>Fill color</td><td>Solid, gradient (linear or radial), or none (transparent)</td></tr><tr><td>Border color</td><td>Any color, or none</td></tr><tr><td>Border width</td><td>0–20 px</td></tr><tr><td>Border style</td><td>Solid, dashed, dotted</td></tr><tr><td>Corner radius</td><td>0–50 px (rectangles only)</td></tr><tr><td>Opacity</td><td>0–100%</td></tr><tr><td>Shadow</td><td>Offset, blur, and color</td></tr></tbody></table><h2 id="line-and-arrow-options" tabindex="-1">Line and arrow options <a class="header-anchor" href="#line-and-arrow-options" aria-label="Permalink to &quot;Line and arrow options&quot;">​</a></h2><p>For <strong>Line</strong> and <strong>Arrow</strong> elements:</p><ul><li>Set the <strong>start</strong> and <strong>end</strong> arrowhead style: none, open arrow, filled arrow, circle</li><li>Set <strong>stroke width</strong> and <strong>stroke style</strong> (solid, dashed)</li><li>Lines snap to 45° angles when you hold <code>Shift</code> while drawing</li></ul><h2 id="layering" tabindex="-1">Layering <a class="header-anchor" href="#layering" aria-label="Permalink to &quot;Layering&quot;">​</a></h2><p>Use the layer controls to adjust the stacking order of overlapping elements:</p><ul><li><strong>Bring to Front</strong> — move in front of all other elements</li><li><strong>Send to Back</strong> — move behind all other elements</li><li><strong>Bring Forward</strong> — move up one layer</li><li><strong>Send Backward</strong> — move down one layer</li></ul><p>Right-click an element and choose the layer option, or use the toolbar buttons.</p><h2 id="grouping-elements" tabindex="-1">Grouping elements <a class="header-anchor" href="#grouping-elements" aria-label="Permalink to &quot;Grouping elements&quot;">​</a></h2><p>Select multiple elements (click one, then <code>Shift+click</code> others, or drag a selection box) and press <code>Ctrl+G</code> to group them. A grouped set of elements can be moved and resized as a single unit.</p><p>Press <code>Ctrl+Shift+G</code> to ungroup.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Groups are useful for building diagrams or slide components that you want to reuse. After grouping, right-click and choose <strong>Save as Template</strong> to add the group to your template library.</p></div>',20)])])}const u=t(n,[["render",i]]);export{c as __pageData,u as default};
